"use client";

import { Lightbox } from "./Lightbox.js";

export * from "./consts.js";
export * from "./types.js";
export * from "./props.js";
export * from "./utils.js";
export * from "./config.js";

export * from "./hooks/index.js";
export * from "./contexts/index.js";
export * from "./components/index.js";
export * from "./modules/index.js";

export * from "./Lightbox.js";

export default Lightbox;

import * as React from "react";

import { clsx, cssClass, translateLabel } from "../utils.js";
import { useLightboxProps } from "../contexts/index.js";
import { ELEMENT_BUTTON, ELEMENT_ICON } from "../consts.js";
import { Label } from "../types.js";

export type IconButtonProps = React.ComponentProps<"button"> & {
  label: Label;
  icon: React.ElementType;
  renderIcon?: () => React.ReactNode;
};

export const IconButton = React.forwardRef<HTMLButtonElement, IconButtonProps>(function IconButton(
  { label, className, icon: Icon, renderIcon, onClick, style, ...rest },
  ref,
) {
  const { styles, labels } = useLightboxProps();
  const buttonLabel = translateLabel(labels, label);
  const RenderIcon: any = Icon;

  return (
    <button
      ref={ref}
      type="button"
      title={buttonLabel}
      aria-label={buttonLabel}
      className={clsx(cssClass(ELEMENT_BUTTON), className)}
      onClick={onClick}
      style={{ ...style, ...styles.button }}
      {...rest}
    >
      {renderIcon ? renderIcon() : <RenderIcon className={cssClass(ELEMENT_ICON)} style={styles.icon} />}
    </button>
  );
});

import * as React from "react";

function svgIcon(name: string, children: React.ReactNode) {
  const icon = (props: React.SVGProps<SVGSVGElement>) => (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      width="24"
      height="24"
      aria-hidden="true"
      focusable="false"
      {...props}
    >
      {children}
    </svg>
  );
  icon.displayName = name;
  return icon;
}

export function createIcon(name: string, glyph: React.ReactNode) {
  return svgIcon(
    name,
    <g fill="currentColor">
      <path d="M0 0h24v24H0z" fill="none" />
      {glyph}
    </g>,
  );
}

export function createIconDisabled(name: string, glyph: React.ReactNode) {
  return svgIcon(
    name,
    <>
      <defs>
        <mask id="strike">
          <path d="M0 0h24v24H0z" fill="white" />
          <path d="M0 0L24 24" stroke="black" strokeWidth={4} />
        </mask>
      </defs>
      <path d="M0.70707 2.121320L21.878680 23.292883" stroke="currentColor" strokeWidth={2} />
      <g fill="currentColor" mask="url(#strike)">
        <path d="M0 0h24v24H0z" fill="none" />
        {glyph}
      </g>
    </>,
  );
}

export const CloseIcon = createIcon(
  "Close",
  <path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z" />,
);

export const PreviousIcon = createIcon("Previous", <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z" />);

export const NextIcon = createIcon("Next", <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z" />);

export const LoadingIcon = createIcon(
  "Loading",
  <>
    {Array.from({ length: 8 }).map((_, index, array) => (
      <line
        key={index}
        x1="12"
        y1="6.5"
        x2="12"
        y2="1.8"
        strokeLinecap="round"
        strokeWidth="2.6"
        stroke="currentColor"
        strokeOpacity={(1 / array.length) * (index + 1)}
        transform={`rotate(${(360 / array.length) * index}, 12, 12)`}
      />
    ))}
  </>,
);

export const ErrorIcon = createIcon(
  "Error",
  <path d="M21.9,21.9l-8.49-8.49l0,0L3.59,3.59l0,0L2.1,2.1L0.69,3.51L3,5.83V19c0,1.1,0.9,2,2,2h13.17l2.31,2.31L21.9,21.9z M5,18 l3.5-4.5l2.5,3.01L12.17,15l3,3H5z M21,18.17L5.83,3H19c1.1,0,2,0.9,2,2V18.17z" />,
);

import * as React from "react";

import { CarouselSettings, ContainerRect, Render, SlideImage } from "../types.js";
import { clsx, cssClass, hasWindow, isImageFitCover, makeComposePrefix } from "../utils.js";
import { useEventCallback } from "../hooks/index.js";
import { useEvents, useTimeouts } from "../contexts/index.js";
import { ErrorIcon, LoadingIcon } from "./Icons.js";
import {
  activeSlideStatus,
  ELEMENT_ICON,
  SLIDE_STATUS_COMPLETE,
  SLIDE_STATUS_ERROR,
  SLIDE_STATUS_LOADING,
  SLIDE_STATUS_PLACEHOLDER,
  SlideStatus,
} from "../consts.js";

const slidePrefix = makeComposePrefix("slide");
const slideImagePrefix = makeComposePrefix("slide_image");

export type ImageSlideProps = Partial<Pick<CarouselSettings, "imageFit" | "imageProps">> & {
  slide: SlideImage;
  offset?: number;
  render?: Render;
  rect?: ContainerRect;
  onClick?: () => void;
  onLoad?: (image: HTMLImageElement) => void;
  onError?: () => void;
  style?: React.CSSProperties;
};

export function ImageSlide({
  slide: image,
  offset,
  render,
  rect,
  imageFit,
  imageProps,
  onClick,
  onLoad,
  onError,
  style,
}: ImageSlideProps) {
  const [status, setStatus] = React.useState<SlideStatus>(SLIDE_STATUS_LOADING);

  const { publish } = useEvents();
  const { setTimeout } = useTimeouts();

  const imageRef = React.useRef<HTMLImageElement>(null);

  React.useEffect(() => {
    if (offset === 0) {
      publish(activeSlideStatus(status));
    }
  }, [offset, status, publish]);

  const handleLoading = useEventCallback((img: HTMLImageElement) => {
    ("decode" in img ? img.decode() : Promise.resolve())
      .catch(() => {})
      .then(() => {
        if (!img.parentNode) {
          return;
        }
        setStatus(SLIDE_STATUS_COMPLETE);

        // this is a workaround for Zoom plugin's preload image swap
        // otherwise the 'complete' status does not get published
        setTimeout(() => {
          onLoad?.(img);
        }, 0);
      });
  });

  const setImageRef = React.useCallback(
    (img: HTMLImageElement | null) => {
      imageRef.current = img;

      if (img?.complete) {
        handleLoading(img);
      }
    },
    [handleLoading],
  );

  const handleOnLoad = React.useCallback(
    (event: React.SyntheticEvent<HTMLImageElement>) => {
      handleLoading(event.currentTarget);
    },
    [handleLoading],
  );

  const handleOnError = useEventCallback(() => {
    setStatus(SLIDE_STATUS_ERROR);

    onError?.();
  });

  const cover = isImageFitCover(image, imageFit);

  const nonInfinite = (value: number, fallback: number) => (Number.isFinite(value) ? value : fallback);

  const maxWidth = nonInfinite(
    Math.max(...(image.srcSet?.map((x) => x.width) ?? []).concat(image.width ? [image.width] : []).filter(Boolean)),
    imageRef.current?.naturalWidth || 0,
  );

  const maxHeight = nonInfinite(
    Math.max(...(image.srcSet?.map((x) => x.height) ?? []).concat(image.height ? [image.height] : []).filter(Boolean)),
    imageRef.current?.naturalHeight || 0,
  );

  const defaultStyle =
    maxWidth && maxHeight
      ? {
          maxWidth: `min(${maxWidth}px, 100%)`,
          maxHeight: `min(${maxHeight}px, 100%)`,
        }
      : {
          maxWidth: "100%",
          maxHeight: "100%",
        };

  const srcSet = image.srcSet
    ?.slice()
    .sort((a, b) => a.width - b.width)
    .map((item) => `${item.src} ${item.width}w`)
    .join(", ");

  const estimateActualWidth = () =>
    rect && !cover && image.width && image.height ? (rect.height / image.height) * image.width : Number.MAX_VALUE;

  const sizes =
    srcSet && rect && hasWindow() ? `${Math.round(Math.min(estimateActualWidth(), rect.width))}px` : undefined;

  const {
    style: imagePropsStyle,
    className: imagePropsClassName,
    ...restImageProps
  } = (typeof imageProps === "function" ? imageProps(image) : imageProps) || {};

  return (
    <>
      {/* eslint-disable-next-line jsx-a11y/click-events-have-key-events,jsx-a11y/no-noninteractive-element-interactions */}
      <img
        ref={setImageRef}
        onLoad={handleOnLoad}
        onError={handleOnError}
        onClick={onClick}
        draggable={false}
        className={clsx(
          cssClass(slideImagePrefix()),
          cover && cssClass(slideImagePrefix("cover")),
          status !== SLIDE_STATUS_COMPLETE && cssClass(slideImagePrefix("loading")),
          imagePropsClassName,
        )}
        style={{ ...defaultStyle, ...style, ...imagePropsStyle }}
        {...restImageProps}
        alt={image.alt ?? ""}
        sizes={sizes}
        srcSet={srcSet}
        src={image.src}
      />

      {status !== SLIDE_STATUS_COMPLETE && (
        <div className={cssClass(slidePrefix(SLIDE_STATUS_PLACEHOLDER))}>
          {status === SLIDE_STATUS_LOADING &&
            (render?.iconLoading ? (
              render.iconLoading()
            ) : (
              <LoadingIcon className={clsx(cssClass(ELEMENT_ICON), cssClass(slidePrefix(SLIDE_STATUS_LOADING)))} />
            ))}
          {status === SLIDE_STATUS_ERROR &&
            (render?.iconError ? (
              render.iconError()
            ) : (
              <ErrorIcon className={clsx(cssClass(ELEMENT_ICON), cssClass(slidePrefix(SLIDE_STATUS_ERROR)))} />
            ))}
        </div>
      )}
    </>
  );
}

export * from "./IconButton.js";
export * from "./Icons.js";
