import * as React from "react";

import { makeUseContext } from "../utils.js";

export type A11yContextType = {
  focusWithin: boolean;
  trackFocusWithin: (
    onFocus?: React.FocusEventHandler,
    onBlur?: React.FocusEventHandler,
  ) => {
    onFocus: React.FocusEventHandler;
    onBlur: React.FocusEventHandler;
  };
  autoPlaying: boolean;
  setAutoPlaying: (value: boolean) => void;
};

export const A11yContext = React.createContext<A11yContextType | null>(null);

export const useA11yContext = makeUseContext("useA11yContext", "A11yContext", A11yContext);

export function A11yContextProvider({ children }: React.PropsWithChildren) {
  const [focusWithin, setFocusWithin] = React.useState(false);
  const [autoPlaying, setAutoPlaying] = React.useState(false);

  const context = React.useMemo(() => {
    const trackFocusWithin: A11yContextType["trackFocusWithin"] = (onFocus, onBlur) => {
      const trackAndDelegate = (focusWithinValue: boolean) => (event: React.FocusEvent) => {
        if (!event.currentTarget.contains(event.relatedTarget)) {
          setFocusWithin(focusWithinValue);
        }

        (focusWithinValue ? onFocus : onBlur)?.(event);
      };

      return {
        onFocus: trackAndDelegate(true),
        onBlur: trackAndDelegate(false),
      };
    };

    return { focusWithin, trackFocusWithin, autoPlaying, setAutoPlaying };
  }, [focusWithin, autoPlaying]);

  return <A11yContext.Provider value={context}>{children}</A11yContext.Provider>;
}

import * as React from "react";

import { makeUseContext } from "../utils.js";

export type DocumentContextType = {
  getOwnerDocument: (node?: Node | null) => Document;
  getOwnerWindow: (node?: Node | null) => Window;
};

export const DocumentContext = React.createContext<DocumentContextType | null>(null);

export const useDocumentContext = makeUseContext("useDocument", "DocumentContext", DocumentContext);

export type DocumentContextProviderProps = React.PropsWithChildren & {
  nodeRef: React.RefObject<Node | null>;
};

export function DocumentContextProvider({ nodeRef, children }: DocumentContextProviderProps) {
  const context = React.useMemo(() => {
    const getOwnerDocument = (node?: Node | null) => (node || nodeRef.current)?.ownerDocument || document;
    const getOwnerWindow = (node?: Node | null) => getOwnerDocument(node)?.defaultView || window;
    return { getOwnerDocument, getOwnerWindow };
  }, [nodeRef]);

  return <DocumentContext.Provider value={context}>{children}</DocumentContext.Provider>;
}

import * as React from "react";

import { makeUseContext } from "../utils.js";
import { EventTypes } from "../types.js";

export type Topic = keyof EventTypes;

export type Event<T extends Topic> = EventTypes[T];

export type EventCallback<T extends Topic> = (...args: Event<T> extends void ? [] : [event: Event<T>]) => void;

export type Subscribe = <T extends Topic>(topic: T, callback: EventCallback<T>) => () => void;

export type Unsubscribe = <T extends Topic>(topic: T, callback: EventCallback<T>) => void;

export type Publish = <T extends Topic>(
  ...args: Event<T> extends void ? [topic: T] : [topic: T, event: Event<T>]
) => void;

export type EventsContextType = {
  subscribe: Subscribe;
  unsubscribe: Unsubscribe;
  publish: Publish;
};

export const EventsContext = React.createContext<EventsContextType | null>(null);

export const useEvents = makeUseContext("useEvents", "EventsContext", EventsContext);

export function EventsProvider({ children }: React.PropsWithChildren) {
  const [subscriptions] = React.useState<{ [T in Topic]?: EventCallback<T>[] }>({});

  React.useEffect(
    () => () => {
      (Object.keys(subscriptions) as Topic[]).forEach((topic) => delete subscriptions[topic]);
    },
    [subscriptions],
  );

  const context = React.useMemo<EventsContextType>(() => {
    const unsubscribe = <T extends Topic>(topic: T, callback: EventCallback<T>) => {
      subscriptions[topic]?.splice(
        0,
        subscriptions[topic]!.length,
        ...subscriptions[topic]!.filter((cb) => cb !== callback),
      );
    };

    const subscribe = <T extends Topic>(topic: T, callback: EventCallback<T>) => {
      if (!subscriptions[topic]) {
        subscriptions[topic] = [];
      }
      subscriptions[topic]!.push(callback);

      return () => unsubscribe(topic, callback);
    };

    const publish = <T extends Topic>(...[topic, event]: Event<T> extends void ? [T] : [T, Event<T>]) => {
      // most likely culprit - https://github.com/microsoft/TypeScript/issues/29131
      subscriptions[topic]?.forEach((callback) => (callback as unknown as (event?: Event<T>) => void)(event));
    };

    return { publish, subscribe, unsubscribe };
  }, [subscriptions]);

  return <EventsContext.Provider value={context}>{children}</EventsContext.Provider>;
}

