import * as React from "react";

import { parseInt } from "../utils.js";
import { useLayoutEffect } from "./useLayoutEffect.js";
import { useMotionPreference } from "./useMotionPreference.js";

function currentTransformation(node: HTMLElement) {
  let x = 0;
  let y = 0;
  let z = 0;
  const matrix = window.getComputedStyle(node).transform;
  const matcher = matrix.match(/matrix.*\((.+)\)/);
  if (matcher) {
    const values = matcher[1].split(",").map(parseInt);
    if (values.length === 6) {
      x = values[4];
      y = values[5];
    } else if (values.length === 16) {
      x = values[12];
      y = values[13];
      z = values[14];
    }
  }
  return { x, y, z };
}

export type ComputeAnimation<T> = (
  snapshot: T,
  rect: DOMRect,
  translate: { x: number; y: number; z: number },
) =>
  | {
      keyframes: Keyframe[];
      duration: number;
      easing?: string;
      onfinish?: () => void;
    }
  | undefined;

export function useAnimation<T>(nodeRef: React.RefObject<HTMLElement | null>, computeAnimation: ComputeAnimation<T>) {
  const snapshot = React.useRef<T>(undefined);
  const animation = React.useRef<Animation>(undefined);

  const reduceMotion = useMotionPreference();

  useLayoutEffect(() => {
    if (nodeRef.current && snapshot.current !== undefined && !reduceMotion) {
      const { keyframes, duration, easing, onfinish } =
        computeAnimation(
          snapshot.current,
          nodeRef.current.getBoundingClientRect(),
          currentTransformation(nodeRef.current),
        ) || {};

      if (keyframes && duration) {
        animation.current?.cancel();
        animation.current = undefined;

        try {
          animation.current = nodeRef.current.animate?.(keyframes, { duration, easing });
        } catch (err) {
          // eslint-disable-next-line no-console
          console.error(err);
        }

        if (animation.current) {
          animation.current.onfinish = () => {
            animation.current = undefined;

            onfinish?.();
          };
        }
      }
    }

    snapshot.current = undefined;
  });

  return {
    prepareAnimation: (currentSnapshot: T | undefined) => {
      snapshot.current = currentSnapshot;
    },
    isAnimationPlaying: () => animation.current?.playState === "running",
  };
}

import * as React from "react";

import { ContainerRect } from "../types.js";

export function useContainerRect<T extends HTMLElement = HTMLElement>() {
  const containerRef = React.useRef<T>(null);
  const observerRef = React.useRef<ResizeObserver>(undefined);
  const [containerRect, setContainerRect] = React.useState<ContainerRect>();

  const setContainerRef = React.useCallback((node: T | null) => {
    containerRef.current = node;

    if (observerRef.current) {
      observerRef.current.disconnect();
      observerRef.current = undefined;
    }

    const updateContainerRect = () => {
      if (node) {
        const styles = window.getComputedStyle(node);

        const parse = (value: string) => parseFloat(value) || 0;

        setContainerRect({
          width: Math.round(node.clientWidth - parse(styles.paddingLeft) - parse(styles.paddingRight)),
          height: Math.round(node.clientHeight - parse(styles.paddingTop) - parse(styles.paddingBottom)),
        });
      } else {
        setContainerRect(undefined);
      }
    };

    updateContainerRect();

    if (node && typeof ResizeObserver !== "undefined") {
      observerRef.current = new ResizeObserver(updateContainerRect);
      observerRef.current.observe(node);
    }
  }, []);

  return { setContainerRef, containerRef, containerRect };
}

import * as React from "react";

import { useTimeouts } from "../contexts/Timeouts.js";

export function useDelay() {
  const timeoutId = React.useRef<number>(undefined);
  const { setTimeout, clearTimeout } = useTimeouts();

  return React.useCallback(
    (callback: () => void, delay: number) => {
      clearTimeout(timeoutId.current);
      timeoutId.current = setTimeout(callback, delay > 0 ? delay : 0);
    },
    [setTimeout, clearTimeout],
  );
}

import * as React from "react";

import { useLayoutEffect } from "./useLayoutEffect.js";

export function useEventCallback<Args extends unknown[], Return>(
  fn: (...args: Args) => Return,
): (...args: Args) => Return {
  const ref = React.useRef(fn);
  useLayoutEffect(() => {
    ref.current = fn;
  });
  return React.useCallback((...args: Args) => ref.current?.(...args), []);
}

import * as React from "react";

export function setRef<T>(
  ref: React.MutableRefObject<T | null> | ((instance: T | null) => void) | null | undefined,
  value: T | null,
): void {
  if (typeof ref === "function") {
    ref(value);
  } else if (ref) {
    ref.current = value;
  }
}

export function useForkRef<InstanceA, InstanceB>(
  refA: React.Ref<InstanceA> | null | undefined,
  refB: React.Ref<InstanceB> | null | undefined,
): React.Ref<InstanceA & InstanceB> | null {
  return React.useMemo(
    () =>
      refA == null && refB == null
        ? null
        : (refValue) => {
            setRef(refA, refValue);
            setRef(refB, refValue);
          },
    [refA, refB],
  );
}

import * as React from "react";

import { hasWindow } from "../utils.js";

export const useLayoutEffect = hasWindow() ? React.useLayoutEffect : React.useEffect;

import * as React from "react";

import { useLayoutEffect } from "./useLayoutEffect.js";

export function useLoseFocus(focus: () => void, disabled = false) {
  const focused = React.useRef(false);

  useLayoutEffect(() => {
    if (disabled && focused.current) {
      focused.current = false;
      focus();
    }
  }, [disabled, focus]);

  const onFocus = React.useCallback(() => {
    focused.current = true;
  }, []);

  const onBlur = React.useCallback(() => {
    focused.current = false;
  }, []);

  return { onFocus, onBlur };
}

import * as React from "react";

export function useMotionPreference() {
  const [reduceMotion, setReduceMotion] = React.useState(false);

  React.useEffect(() => {
    const mediaQuery = window.matchMedia?.("(prefers-reduced-motion: reduce)");
    setReduceMotion(mediaQuery?.matches);
    const listener = (event: MediaQueryListEvent) => setReduceMotion(event.matches);
    mediaQuery?.addEventListener?.("change", listener);
    return () => mediaQuery?.removeEventListener?.("change", listener);
  }, []);

  return reduceMotion;
}

