  setCarouselRef: React.Ref<HTMLDivElement>;
  toolbarWidth: number | undefined;
  setToolbarWidth: (width: number | undefined) => void;
};

export const ControllerContext = React.createContext<ControllerContextType | null>(null);

export const useController = makeUseContext("useController", "ControllerContext", ControllerContext);

export function Controller({ children, ...props }: ComponentProps) {
  const { carousel, animation, controller, on, styles, render } = props;
  const { closeOnPullUp, closeOnPullDown, preventDefaultWheelX, preventDefaultWheelY } = controller;

  const [toolbarWidth, setToolbarWidth] = React.useState<number>();

  const state = useLightboxState();
  const dispatch = useLightboxDispatch();

  const [swipeState, setSwipeState] = React.useState(SwipeState.NONE);
  const swipeOffset = React.useRef(0);
  const pullOffset = React.useRef(0);
  const pullOpacity = React.useRef(1);

  const { registerSensors, subscribeSensors } = useSensors<HTMLDivElement>();
  const { subscribe, publish } = useEvents();

  const cleanupAnimationIncrement = useDelay();
  const cleanupSwipeOffset = useDelay();
  const cleanupPullOffset = useDelay();

  const { containerRef, setContainerRef, containerRect } = useContainerRect<HTMLDivElement>();
  const handleContainerRef = useForkRef(
    usePreventWheelDefaults({ preventDefaultWheelX, preventDefaultWheelY }),
    setContainerRef,
  );

  const carouselRef = React.useRef<HTMLDivElement>(null);
  const setCarouselRef = useForkRef(carouselRef, undefined);

  const { getOwnerDocument } = useDocumentContext();

  const isRTL = useRTL();

  const rtl = (value?: number) => (isRTL ? -1 : 1) * (typeof value === "number" ? value : 1);

  const focus = useEventCallback(() => containerRef.current?.focus());

  const getLightboxProps = useEventCallback(() => props);
  const getLightboxState = useEventCallback(() => state);

  const prev: ControllerRef["prev"] = React.useCallback((params) => publish(ACTION_PREV, params), [publish]);
  const next: ControllerRef["next"] = React.useCallback((params) => publish(ACTION_NEXT, params), [publish]);
  const close: ControllerRef["close"] = React.useCallback(() => publish(ACTION_CLOSE), [publish]);

  const isSwipeValid = (offset: number) =>
    !(
      carousel.finite &&
      ((rtl(offset) > 0 && state.currentIndex === 0) ||
        (rtl(offset) < 0 && state.currentIndex === state.slides.length - 1))
    );

  const setSwipeOffset = (offset: number) => {
    swipeOffset.current = offset;

    containerRef.current?.style.setProperty(cssVar("swipe_offset"), `${Math.round(offset)}px`);
  };

  const setPullOffset = (offset: number) => {
    pullOffset.current = offset;
    pullOpacity.current = (() => {
      const threshold = 60;
      const minOpacity = 0.5;
      const offsetValue = (() => {
        if (closeOnPullDown && offset > 0) return offset;
        if (closeOnPullUp && offset < 0) return -offset;
        return 0;
      })();
      return Math.min(Math.max(round(1 - (offsetValue / threshold) * (1 - minOpacity), 2), minOpacity), 1);
    })();

    containerRef.current?.style.setProperty(cssVar("pull_offset"), `${Math.round(offset)}px`);
    containerRef.current?.style.setProperty(cssVar("pull_opacity"), `${pullOpacity.current}`);
  };

  const { prepareAnimation: preparePullAnimation } = useAnimation<{
    rect: DOMRect;
    opacity: number;
    duration: number;
  }>(carouselRef, (snapshot, rect, translate) => {
    if (carouselRef.current && containerRect) {
      return {
        keyframes: [
          {
            transform: `translate(0, ${snapshot.rect.y - rect.y + translate.y}px)`,
            opacity: snapshot.opacity,
          },
          { transform: "translate(0, 0)", opacity: 1 },
        ],
        duration: snapshot.duration,
        easing: animation.easing.fade,
      };
    }
    return undefined;
  });

  const pull = (offset: number, cancel?: boolean) => {
    if (closeOnPullUp || closeOnPullDown) {
      setPullOffset(offset);

      let duration = 0;

      if (carouselRef.current) {
        duration = animation.fade * (cancel ? 2 : 1);

        preparePullAnimation({
          rect: carouselRef.current.getBoundingClientRect(),
          opacity: pullOpacity.current,
          duration,
        });
      }

      cleanupPullOffset(() => {
        setPullOffset(0);
        setSwipeState(SwipeState.NONE);
      }, duration);

      setSwipeState(SwipeState.ANIMATION);

      if (!cancel) {
        close();
      }
    }
  };

  const { prepareAnimation, isAnimationPlaying } = useAnimation<{ rect: DOMRect; index: number }>(
    carouselRef,
    (snapshot, rect, translate) => {
      if (carouselRef.current && containerRect && state.animation?.duration) {
        const parsedSpacing = parseLengthPercentage(carousel.spacing);
        const spacingValue =
          (parsedSpacing.percent ? (parsedSpacing.percent * containerRect.width) / 100 : parsedSpacing.pixel) || 0;

        return {
          keyframes: [
            {
              transform: `translate(${
                rtl(state.globalIndex - snapshot.index) * (containerRect.width + spacingValue) +
                snapshot.rect.x -
                rect.x +
                translate.x
              }px, 0)`,
            },
            { transform: "translate(0, 0)" },
          ],
          duration: state.animation.duration,
          easing: state.animation.easing,
        };
      }
      return undefined;
    },
  );

  const swipe = useEventCallback(
    (action: { direction?: "prev" | "next"; count?: number; offset?: number; duration?: number }) => {
      const currentSwipeOffset = action.offset || 0;
      const swipeDuration = !currentSwipeOffset ? (animation.navigation ?? animation.swipe) : animation.swipe;
      const swipeEasing =
        !currentSwipeOffset && !isAnimationPlaying() ? animation.easing.navigation : animation.easing.swipe;

      let { direction } = action;
      const count = action.count ?? 1;

      let newSwipeState = SwipeState.ANIMATION;
      let newSwipeAnimationDuration = swipeDuration * count;

      if (!direction) {
        const containerWidth = containerRect?.width;

        const elapsedTime = action.duration || 0;
        const expectedTime = containerWidth
          ? (swipeDuration / containerWidth) * Math.abs(currentSwipeOffset)
          : swipeDuration;

        if (count !== 0) {
          if (elapsedTime < expectedTime) {
            newSwipeAnimationDuration =
              (newSwipeAnimationDuration / expectedTime) * Math.max(elapsedTime, expectedTime / 5);
          } else if (containerWidth) {
            newSwipeAnimationDuration =
              (swipeDuration / containerWidth) * (containerWidth - Math.abs(currentSwipeOffset));
          }

          direction = rtl(currentSwipeOffset) > 0 ? ACTION_PREV : ACTION_NEXT;
        } else {
          newSwipeAnimationDuration = swipeDuration / 2;
        }
      }

      let increment = 0;
      if (direction === ACTION_PREV) {
        if (isSwipeValid(rtl(1))) {
          increment = -count;
        } else {
          newSwipeState = SwipeState.NONE;
          newSwipeAnimationDuration = swipeDuration;
        }
      } else if (direction === ACTION_NEXT) {
        if (isSwipeValid(rtl(-1))) {
          increment = count;
        } else {
          newSwipeState = SwipeState.NONE;
          newSwipeAnimationDuration = swipeDuration;
        }
      }

      newSwipeAnimationDuration = Math.round(newSwipeAnimationDuration);

      cleanupSwipeOffset(() => {
        setSwipeOffset(0);
        setSwipeState(SwipeState.NONE);
      }, newSwipeAnimationDuration);

      if (carouselRef.current) {
        prepareAnimation({
          rect: carouselRef.current.getBoundingClientRect(),
          index: state.globalIndex,
        });
      }

      setSwipeState(newSwipeState);

      publish(ACTION_SWIPE, {
        type: "swipe",
        increment,
        duration: newSwipeAnimationDuration,
        easing: swipeEasing,
      });
    },
  );

  React.useEffect(() => {
    if (state.animation?.increment && state.animation?.duration) {
      cleanupAnimationIncrement(() => dispatch({ type: "swipe", increment: 0 }), state.animation.duration);
    }
  }, [state.animation, dispatch, cleanupAnimationIncrement]);

  const swipeParams = [
    subscribeSensors,
    isSwipeValid,
    containerRect?.width || 0,
    animation.swipe,
    // onSwipeStart
    () => setSwipeState(SwipeState.SWIPE),
    // onSwipeProgress
    (offset: number) => setSwipeOffset(offset),
    // onSwipeFinish
    (offset: number, duration: number) => swipe({ offset, duration, count: 1 }),
    // onSwipeCancel
    (offset: number) => swipe({ offset, count: 0 }),
  ] as const;

  const pullParams = [
    // onPullStart
    () => {
      if (closeOnPullDown) {
        setSwipeState(SwipeState.PULL);
      }
    },
    // onPullProgress
    (offset: number) => setPullOffset(offset),
    // onPullFinish
    (offset: number) => pull(offset),
    // onPullCancel
    (offset: number) => pull(offset, true),
  ] as const;

  usePointerSwipe(controller, ...swipeParams, closeOnPullUp, closeOnPullDown, ...pullParams, close);

  useWheelSwipe(swipeState, ...swipeParams);

  const focusOnMount = useEventCallback(() => {
    // capture focus only when rendered inside a portal
    if (
      controller.focus &&
      getOwnerDocument().querySelector(`.${cssClass(MODULE_PORTAL)} .${cssClass(cssContainerPrefix())}`)
    ) {
      focus();
    }
  });

  React.useEffect(focusOnMount, [focusOnMount]);

  const onViewCallback = useEventCallback(() => {
    on.view?.({ index: state.currentIndex });
  });

  React.useEffect(onViewCallback, [state.globalIndex, onViewCallback]);

  React.useEffect(
    () =>
      cleanup(
        subscribe(ACTION_PREV, (action) => swipe({ direction: ACTION_PREV, ...action })),
        subscribe(ACTION_NEXT, (action) => swipe({ direction: ACTION_NEXT, ...action })),
        subscribe(ACTION_SWIPE, (action) => dispatch(action)),
      ),
    [subscribe, swipe, dispatch],
  );

  const context = React.useMemo<ControllerContextType>(
    () => ({
      prev,
      next,
      close,
      focus,
      // we are not going to render context provider when containerRect is undefined
      slideRect: containerRect ? computeSlideRect(containerRect, carousel.padding) : { width: 0, height: 0 },
      containerRect: containerRect || { width: 0, height: 0 },
      subscribeSensors,
      containerRef,
      setCarouselRef,
      toolbarWidth,
      setToolbarWidth,
    }),
    [
      prev,
      next,
      close,
      focus,
      subscribeSensors,
      containerRect,
      containerRef,
      setCarouselRef,
      toolbarWidth,
      setToolbarWidth,
      carousel.padding,
    ],
  );

  React.useImperativeHandle(
    controller.ref,
    () => ({
      prev,
      next,
      close,
      focus,
      getLightboxProps,
      getLightboxState,
    }),
    [prev, next, close, focus, getLightboxProps, getLightboxState],
  );

  return (
    <div
      ref={handleContainerRef}
      className={clsx(cssClass(cssContainerPrefix()), cssClass(CLASS_FLEX_CENTER))}
      style={{
        ...(swipeState === SwipeState.SWIPE
          ? { [cssVar("swipe_offset")]: `${Math.round(swipeOffset.current)}px` }
          : null),
        ...(swipeState === SwipeState.PULL
          ? {
              [cssVar("pull_offset")]: `${Math.round(pullOffset.current)}px`,
              [cssVar("pull_opacity")]: `${pullOpacity.current}`,
            }
          : null),
        ...(controller.touchAction !== "none" ? { [cssVar("controller_touch_action")]: controller.touchAction } : null),
        ...styles.container,
      }}
      tabIndex={-1}
      {...registerSensors}
    >
      {containerRect && (
        <ControllerContext.Provider value={context}>
          {children}
          {render.controls?.()}
        </ControllerContext.Provider>
      )}
    </div>
  );
}

export const ControllerModule = createModule(MODULE_CONTROLLER, Controller);

export * from "./SwipeState.js";
export * from "./usePointerSwipe.js";
export * from "./usePreventWheelDefaults.js";
export * from "./useWheelSwipe.js";
export * from "./Controller.js";

export enum SwipeState {
  NONE,
  SWIPE,
  PULL,
  ANIMATION,
}

import * as React from "react";

import { ControllerSettings } from "../../types.js";
import { UseSensors } from "../../hooks/useSensors.js";
import { useEventCallback } from "../../hooks/useEventCallback.js";
import { usePointerEvents } from "../../hooks/usePointerEvents.js";
import { cssClass } from "../../utils.js";
import { CLASS_SLIDE, CLASS_SLIDE_WRAPPER } from "../../consts.js";

enum Gesture {
  NONE,
  SWIPE,
  PULL,
}

const SWIPE_THRESHOLD = 30;

export function usePointerSwipe<T extends Element = Element>(
  { disableSwipeNavigation, closeOnBackdropClick }: ControllerSettings,
  subscribeSensors: UseSensors<T>["subscribeSensors"],
  isSwipeValid: (offset: number) => boolean,
  containerWidth: number,
  swipeAnimationDuration: number,
  onSwipeStart: () => void,
  onSwipeProgress: (offset: number) => void,
  onSwipeFinish: (offset: number, duration: number) => void,
  onSwipeCancel: (offset: number) => void,
  pullUpEnabled: boolean,
  pullDownEnabled: boolean,
  onPullStart: () => void,
  onPullProgress: (offset: number) => void,
  onPullFinish: (offset: number, duration: number) => void,
  onPullCancel: (offset: number) => void,
  onClose: () => void,
) {
  const offset = React.useRef<number>(0);
  const pointers = React.useRef<React.PointerEvent[]>([]);
  const activePointer = React.useRef<number>(undefined);
  const startTime = React.useRef<number>(0);
  const gesture = React.useRef(Gesture.NONE);

  const clearPointer = React.useCallback((event: React.PointerEvent) => {
    if (activePointer.current === event.pointerId) {
      activePointer.current = undefined;
      gesture.current = Gesture.NONE;
    }

    const currentPointers = pointers.current;
    currentPointers.splice(
      0,
      currentPointers.length,
      ...currentPointers.filter((p) => p.pointerId !== event.pointerId),
    );
  }, []);

  const addPointer = React.useCallback(
    (event: React.PointerEvent) => {
      clearPointer(event);
      event.persist();
      pointers.current.push(event);
    },
    [clearPointer],
  );

  const lookupPointer = React.useCallback(
    (event: React.PointerEvent) => pointers.current.find(({ pointerId }) => event.pointerId === pointerId),
    [],
  );

  const onPointerDown = useEventCallback((event: React.PointerEvent) => {
    addPointer(event);
  });

  const exceedsPullThreshold = (value: number, threshold: number) =>
    (pullDownEnabled && value > threshold) || (pullUpEnabled && value < -threshold);

  const onPointerUp = useEventCallback((event: React.PointerEvent) => {
    const pointer = lookupPointer(event);
    if (pointer) {
      if (activePointer.current === event.pointerId) {
        const duration = Date.now() - startTime.current;
        const currentOffset = offset.current;

        if (gesture.current === Gesture.SWIPE) {
          if (
            Math.abs(currentOffset) > 0.3 * containerWidth ||
            (Math.abs(currentOffset) > 5 && duration < swipeAnimationDuration)
          ) {
            onSwipeFinish(currentOffset, duration);
          } else {
            onSwipeCancel(currentOffset);
          }
        } else if (gesture.current === Gesture.PULL) {
          if (exceedsPullThreshold(currentOffset, 2 * SWIPE_THRESHOLD)) {
            onPullFinish(currentOffset, duration);
          } else {
            onPullCancel(currentOffset);
          }
        }

        offset.current = 0;
        gesture.current = Gesture.NONE;
      } else {
        // Handle click events
        const { target } = event;
        if (
          closeOnBackdropClick &&
          target instanceof HTMLElement &&
          target === pointer.target &&
          (target.classList.contains(cssClass(CLASS_SLIDE)) || target.classList.contains(cssClass(CLASS_SLIDE_WRAPPER)))
        ) {
          onClose();
        }
      }
    }

    clearPointer(event);
  });

  const onPointerMove = useEventCallback((event: React.PointerEvent) => {
    const pointer = lookupPointer(event);
    if (pointer) {
      const isCurrentPointer = activePointer.current === event.pointerId;

      if (event.buttons === 0) {
        // 2 known scenarios when we may end up here:
        // 1) active pointer must have been released while over an opaque element (https://github.com/igordanchenko/yet-another-react-lightbox/issues/48)
        // 2) out-of-order onpointermove / onpointerup events in Chrome (https://github.com/igordanchenko/yet-another-react-lightbox/issues/59)
        if (isCurrentPointer && offset.current !== 0) {
          onPointerUp(event);
        } else {
          clearPointer(pointer);
        }
        return;
      }

      const deltaX = event.clientX - pointer.clientX;
      const deltaY = event.clientY - pointer.clientY;

      // no gesture in progress
      if (activePointer.current === undefined) {
        const startGesture = (newGesture: Gesture) => {
          addPointer(event);

          activePointer.current = event.pointerId;
          startTime.current = Date.now();

          gesture.current = newGesture;
        };

        if (Math.abs(deltaX) > Math.abs(deltaY) && Math.abs(deltaX) > SWIPE_THRESHOLD && isSwipeValid(deltaX)) {
          if (!disableSwipeNavigation) {
            // start swipe gesture
            startGesture(Gesture.SWIPE);
            onSwipeStart();
          }
        } else if (Math.abs(deltaY) > Math.abs(deltaX) && exceedsPullThreshold(deltaY, SWIPE_THRESHOLD)) {
          // start pull-down gesture
          startGesture(Gesture.PULL);
          onPullStart();
        }
      } else if (isCurrentPointer) {
        if (gesture.current === Gesture.SWIPE) {
          offset.current = deltaX;
          onSwipeProgress(deltaX);
        } else if (gesture.current === Gesture.PULL) {
          offset.current = deltaY;
          onPullProgress(deltaY);
        }
      }
    }
  });

  usePointerEvents(subscribeSensors, onPointerDown, onPointerMove, onPointerUp);
}

import * as React from "react";

import { ControllerSettings } from "../../types.js";
import { useEventCallback } from "../../hooks/useEventCallback.js";

/**
 * Prevent default effects of the wheel events:
 * - prevent browser back/forward navigation on touchpad left/right swipe (especially noticeable in Safari)
 * - prevent vertical scroll in inline mode when `scrollToZoom` option is enabled
 * - prevent page zoom when Zoom plugin is enabled
 */
export function usePreventWheelDefaults<T extends HTMLElement = HTMLElement>({
  preventDefaultWheelX,
  preventDefaultWheelY,
}: Pick<ControllerSettings, "preventDefaultWheelX" | "preventDefaultWheelY">) {
  const ref = React.useRef<T>(null);

  const listener = useEventCallback((event: WheelEvent) => {
    const horizontal = Math.abs(event.deltaX) > Math.abs(event.deltaY);
    if ((horizontal && preventDefaultWheelX) || (!horizontal && preventDefaultWheelY) || event.ctrlKey) {
      event.preventDefault();
    }
  });

  return React.useCallback(
    (node: T | null) => {
      if (node) {
        // this has to be done via non-passive native event handler
        node.addEventListener("wheel", listener, { passive: false });
      } else {
        ref.current?.removeEventListener("wheel", listener);
      }

      ref.current = node;
    },
    [listener],
  );
}

import * as React from "react";

import { useEventCallback, UseSensors } from "../../hooks/index.js";
import { useTimeouts } from "../../contexts/index.js";
import { SwipeState } from "./SwipeState.js";
import { EVENT_ON_WHEEL } from "../../consts.js";

export function useWheelSwipe<T extends Element = Element>(
  swipeState: SwipeState,
  subscribeSensors: UseSensors<T>["subscribeSensors"],
  isSwipeValid: (offset: number) => boolean,
  containerWidth: number,
  swipeAnimationDuration: number,
  onSwipeStart: () => void,
  onSwipeProgress: (offset: number) => void,
  onSwipeFinish: (offset: number, duration: number) => void,
  onSwipeCancel: (offset: number) => void,
) {
  const offset = React.useRef(0);
  const intent = React.useRef(0);
  const intentCleanup = React.useRef<number>(undefined);
  const resetCleanup = React.useRef<number>(undefined);
  const wheelInertia = React.useRef(0);
  const wheelInertiaCleanup = React.useRef<number>(undefined);
  const startTime = React.useRef(0);

  const { setTimeout, clearTimeout } = useTimeouts();

  const cancelSwipeIntentCleanup = React.useCallback(() => {
    if (intentCleanup.current) {
      clearTimeout(intentCleanup.current);
      intentCleanup.current = undefined;
    }
  }, [clearTimeout]);

  const cancelSwipeResetCleanup = React.useCallback(() => {
    if (resetCleanup.current) {
      clearTimeout(resetCleanup.current);
      resetCleanup.current = undefined;
    }
  }, [clearTimeout]);

  const handleCleanup = useEventCallback(() => {
    if (swipeState !== SwipeState.SWIPE) {
      offset.current = 0;
      startTime.current = 0;

      cancelSwipeIntentCleanup();
      cancelSwipeResetCleanup();
    }
  });

  React.useEffect(handleCleanup, [swipeState, handleCleanup]);

  const handleCancelSwipe = useEventCallback((currentSwipeOffset: number) => {
    resetCleanup.current = undefined;

    if (offset.current === currentSwipeOffset) {
      onSwipeCancel(offset.current);
    }
  });

  const onWheel = useEventCallback((event: React.WheelEvent) => {
    if (event.ctrlKey) {
      // zoom
      return;
    }

    if (Math.abs(event.deltaY) > Math.abs(event.deltaX)) {
      // pan-y
      return;
    }

    const setWheelInertia = (inertia: number) => {
      wheelInertia.current = inertia;

      clearTimeout(wheelInertiaCleanup.current);

      wheelInertiaCleanup.current =
        inertia > 0
          ? setTimeout(() => {
              wheelInertia.current = 0;
              wheelInertiaCleanup.current = undefined;
            }, 300)
          : undefined;
    };

    if (swipeState === SwipeState.NONE) {
      if (Math.abs(event.deltaX) <= 1.2 * Math.abs(wheelInertia.current)) {
        setWheelInertia(event.deltaX);
        return;
      }

      if (!isSwipeValid(-event.deltaX)) {
        return;
      }

      intent.current += event.deltaX;

      cancelSwipeIntentCleanup();

      if (Math.abs(intent.current) > 30) {
        intent.current = 0;
        setWheelInertia(0);
        startTime.current = Date.now();

        onSwipeStart();
      } else {
        const currentSwipeIntent = intent.current;
        intentCleanup.current = setTimeout(() => {
          intentCleanup.current = undefined;
          if (currentSwipeIntent === intent.current) {
            intent.current = 0;
          }
        }, swipeAnimationDuration);
      }
    } else if (swipeState === SwipeState.SWIPE) {
      let newSwipeOffset = offset.current - event.deltaX;
      newSwipeOffset = Math.min(Math.abs(newSwipeOffset), containerWidth) * Math.sign(newSwipeOffset);
      offset.current = newSwipeOffset;

      onSwipeProgress(newSwipeOffset);

      cancelSwipeResetCleanup();

      if (Math.abs(newSwipeOffset) > 0.2 * containerWidth) {
        setWheelInertia(event.deltaX);

        onSwipeFinish(newSwipeOffset, Date.now() - startTime.current);

        return;
      }

      resetCleanup.current = setTimeout(() => handleCancelSwipe(newSwipeOffset), 2 * swipeAnimationDuration);
    } else {
      setWheelInertia(event.deltaX);
    }
  });

  React.useEffect(() => subscribeSensors(EVENT_ON_WHEEL, onWheel), [subscribeSensors, onWheel]);
}

