export type NavigationButtonProps = {
  label: Label;
  icon: React.ElementType;
  renderIcon?: RenderFunction;
  action: "prev" | "next";
  onClick: () => void;
  disabled?: boolean;
  style?: React.CSSProperties;
};

export function NavigationButton({ label, icon, renderIcon, action, onClick, disabled, style }: NavigationButtonProps) {
  return (
    <IconButton
      label={label}
      icon={icon}
      renderIcon={renderIcon}
      className={cssClass(`navigation_${action}`)}
      disabled={disabled}
      onClick={onClick}
      style={style}
      {...useLoseFocus(useController().focus, disabled)}
    />
  );
}

export function Navigation({ render: { buttonPrev, buttonNext, iconPrev, iconNext }, styles }: ComponentProps) {
  const { prev, next, subscribeSensors } = useController();
  const { prevDisabled, nextDisabled } = useNavigationState();

  useKeyboardNavigation(subscribeSensors);

  return (
    <>
      {buttonPrev ? (
        buttonPrev()
      ) : (
        <NavigationButton
          label="Previous"
          action={ACTION_PREV}
          icon={PreviousIcon}
          renderIcon={iconPrev}
          style={styles.navigationPrev}
          disabled={prevDisabled}
          onClick={prev}
        />
      )}

      {buttonNext ? (
        buttonNext()
      ) : (
        <NavigationButton
          label="Next"
          action={ACTION_NEXT}
          icon={NextIcon}
          renderIcon={iconNext}
          style={styles.navigationNext}
          disabled={nextDisabled}
          onClick={next}
        />
      )}
    </>
  );
}

export const NavigationModule = createModule(MODULE_NAVIGATION, Navigation);

import * as React from "react";

import { useEvents, useLightboxProps } from "../../contexts/index.js";
import { useEventCallback, useRTL, UseSensors, useThrottle } from "../../hooks/index.js";
import {
  ACTION_CLOSE,
  ACTION_NEXT,
  ACTION_PREV,
  EVENT_ON_KEY_DOWN,
  VK_ARROW_LEFT,
  VK_ARROW_RIGHT,
  VK_ESCAPE,
} from "../../consts.js";
import { useNavigationState } from "./useNavigationState.js";

export function useKeyboardNavigation<T extends Element>(subscribeSensors: UseSensors<T>["subscribeSensors"]) {
  const isRTL = useRTL();
  const { publish } = useEvents();
  const { animation, controller } = useLightboxProps();
  const { prevDisabled, nextDisabled } = useNavigationState();

  const throttle = (animation.navigation ?? animation.swipe) / 2;

  const prev = useThrottle(() => publish(ACTION_PREV), throttle);
  const next = useThrottle(() => publish(ACTION_NEXT), throttle);

  const handleKeyDown = useEventCallback((event: React.KeyboardEvent) => {
    switch (event.key) {
      case VK_ESCAPE:
        if (!controller.closeOnEscape) return;
        publish(ACTION_CLOSE);
        break;
      case VK_ARROW_LEFT:
        if (!(isRTL ? nextDisabled : prevDisabled)) (isRTL ? next : prev)();
        break;
      case VK_ARROW_RIGHT:
        if (!(isRTL ? prevDisabled : nextDisabled)) (isRTL ? prev : next)();
        break;
      default:
        return;
    }
    // Prevent parent modals (e.g. Radix UI, MUI) from also acting on this keystroke —
    // without this, pressing Escape inside the lightbox would close both the lightbox
    // and the surrounding dialog.
    event.stopPropagation();
  });

  React.useEffect(() => subscribeSensors(EVENT_ON_KEY_DOWN, handleKeyDown), [subscribeSensors, handleKeyDown]);
}

import { useLightboxProps, useLightboxState } from "../../contexts/index.js";

export function useNavigationState() {
  const { carousel } = useLightboxProps();
  const { slides, currentIndex } = useLightboxState();

  const prevDisabled = slides.length === 0 || (carousel.finite && currentIndex === 0);
  const nextDisabled = slides.length === 0 || (carousel.finite && currentIndex === slides.length - 1);

  return { prevDisabled, nextDisabled };
}

import * as React from "react";

import { ComponentProps } from "../types.js";
import { createModule } from "../config.js";
import { cssClass, parseInt } from "../utils.js";
import { useRTL } from "../hooks/index.js";
import { useDocumentContext } from "../contexts/index.js";
import { CLASS_NO_SCROLL, CLASS_NO_SCROLL_PADDING, MODULE_NO_SCROLL } from "../consts.js";

const noScroll = cssClass(CLASS_NO_SCROLL);
const noScrollPadding = cssClass(CLASS_NO_SCROLL_PADDING);

function isHTMLElement(element: Element): element is HTMLElement {
  return "style" in element;
}

function padScrollbar(element: HTMLElement, padding: number, rtl: boolean) {
  const styles = window.getComputedStyle(element);
  const property = rtl ? "padding-left" : "padding-right";
  const computedValue = rtl ? styles.paddingLeft : styles.paddingRight;
  const originalValue = element.style.getPropertyValue(property);

  element.style.setProperty(property, `${(parseInt(computedValue) || 0) + padding}px`);

  return () => {
    if (originalValue) {
      element.style.setProperty(property, originalValue);
    } else {
      element.style.removeProperty(property);
    }
  };
}

export function NoScroll({ noScroll: { disabled }, children }: ComponentProps) {
  const rtl = useRTL();
  const { getOwnerDocument, getOwnerWindow } = useDocumentContext();

  React.useEffect(() => {
    if (disabled) return () => {};

    const cleanup: (() => void)[] = [];

    const ownerWindow = getOwnerWindow();
    const { body, documentElement } = getOwnerDocument();

    const scrollbar = Math.round(ownerWindow.innerWidth - documentElement.clientWidth);
    if (scrollbar > 0) {
      cleanup.push(padScrollbar(body, scrollbar, rtl));

      const elements = body.getElementsByTagName("*");
      for (let i = 0; i < elements.length; i += 1) {
        const element = elements[i];
        if (
          isHTMLElement(element) &&
          ownerWindow.getComputedStyle(element).getPropertyValue("position") === "fixed" &&
          !element.classList.contains(noScrollPadding)
        ) {
          cleanup.push(padScrollbar(element, scrollbar, rtl));
        }
      }
    }

    body.classList.add(noScroll);

    return () => {
      body.classList.remove(noScroll);

      cleanup.forEach((clean) => clean());
    };
  }, [rtl, disabled, getOwnerDocument, getOwnerWindow]);

  return <>{children}</>;
}

export const NoScrollModule = createModule(MODULE_NO_SCROLL, NoScroll);

import * as React from "react";
import { createPortal } from "react-dom";

import { ComponentProps } from "../types.js";
import { LightboxDefaultProps } from "../props.js";
import { createModule } from "../config.js";
import { clsx, composePrefix, cssClass, cssVar, reflow, translateLabel } from "../utils.js";
import { useEventCallback, useMotionPreference } from "../hooks/index.js";
import { useEvents, useTimeouts } from "../contexts/index.js";
import { LightboxRoot } from "../components/index.js";
import { ACTION_CLOSE, CLASS_NO_SCROLL_PADDING, MODULE_PORTAL } from "../consts.js";

function cssPrefix(value?: string) {
  return composePrefix(MODULE_PORTAL, value);
}

function setAttribute(element: Element, attribute: string, value: string) {
  const previousValue = element.getAttribute(attribute);

  element.setAttribute(attribute, value);

  return () => {
    if (previousValue) {
      element.setAttribute(attribute, previousValue);
    } else {
      element.removeAttribute(attribute);
    }
  };
}

export function Portal({
  portal: { root, container: { className: containerClassName, style: containerStyle, ...containerRest } = {} },
  animation,
  styles,
  className,
  on,
  close,
  labels,
  children,
}: ComponentProps) {
  const [mounted, setMounted] = React.useState(false);
  const [visible, setVisible] = React.useState(false);

  const cleanup = React.useRef<(() => void)[]>([]);
  const restoreFocus = React.useRef<Element>(null);

  const { setTimeout } = useTimeouts();
  const { subscribe } = useEvents();

  const reduceMotion = useMotionPreference();
  const animationDuration = !reduceMotion ? animation.fade : 0;

  React.useEffect(() => {
    setMounted(true);

    return () => {
      setMounted(false);
      setVisible(false);
    };
  }, []);

  const handleCleanup = useEventCallback(() => {
    cleanup.current.forEach((clean) => clean());
    cleanup.current = [];
  });

  const handleClose = useEventCallback(() => {
    setVisible(false);

    handleCleanup();

    on.exiting?.();

    setTimeout(() => {
      on.exited?.();

      close();
    }, animationDuration);
  });

  React.useEffect(() => subscribe(ACTION_CLOSE, handleClose), [subscribe, handleClose]);

  const handleEnter = useEventCallback((node: HTMLDivElement) => {
    reflow(node);

    setVisible(true);

    on.entering?.();

    const elements = node.parentNode?.children ?? [];
    for (let i = 0; i < elements.length; i += 1) {
      const element = elements[i];
      if (["TEMPLATE", "SCRIPT", "STYLE"].indexOf(element.tagName) === -1 && element !== node) {
        cleanup.current.push(setAttribute(element, "inert", ""));
        cleanup.current.push(setAttribute(element, "aria-hidden", "true"));
      }
    }

    cleanup.current.push(() => {
      (restoreFocus.current as HTMLElement | null)?.focus?.();
    });

    setTimeout(() => {
      on.entered?.();
    }, animationDuration);
  });

  const handleRef = React.useCallback(
    (node: HTMLDivElement | null) => {
      if (node) {
        handleEnter(node);
      } else {
        handleCleanup();
      }
    },
    [handleEnter, handleCleanup],
  );

  return mounted
    ? createPortal(
        <LightboxRoot
          ref={handleRef}
          className={clsx(
            className,
            containerClassName,
            cssClass(cssPrefix()),
            cssClass(CLASS_NO_SCROLL_PADDING),
            visible && cssClass(cssPrefix("open")),
          )}
          aria-modal
          role="dialog"
          aria-label={translateLabel(labels, "Lightbox")}
          style={{
            ...(animation.fade !== LightboxDefaultProps.animation.fade
              ? { [cssVar("fade_animation_duration")]: `${animationDuration}ms` }
              : null),
            ...(animation.easing.fade !== LightboxDefaultProps.animation.easing.fade
              ? { [cssVar("fade_animation_timing_function")]: animation.easing.fade }
              : null),
            ...styles.root,
            ...containerStyle,
          }}
          onFocus={(event) => {
            if (!restoreFocus.current) {
              restoreFocus.current = event.relatedTarget;
            }
          }}
          {...containerRest}
        >
          {children}
        </LightboxRoot>,
        (typeof root === "function" ? root() : root) || document.body,
      )
    : null;
}

export const PortalModule = createModule(MODULE_PORTAL, Portal);

